import React, { useEffect, useRef } from 'react';
import '../style/TextBlurbImg.css';
import '../images/about-text-blurb.svg';

function TextBlurbImg(props) {
    const h2_ref = useRef();
    const div_ref = useRef();
    const img_ref = useRef();
    const mobile_img = useRef();
    const info_blurb = useRef();
    useEffect(() => {
        if (window.innerWidth < 550) {
            if (mobile_img.current.clientHeight > 300) {
                info_blurb.current.style.marginTop = "-20vh";
            }
            else {
                info_blurb.current.style.marginTop = "-10vh";
            }
            if (div_ref.current.clientHeight > 500) {
                h2_ref.current.style.marginBottom = "-5vh";
            }
            else if (div_ref.current.clientHeight > 350) {
                h2_ref.current.style.marginBottom = "-3vh";
            }
        }
        else if (window.innerWidth > 550) {
            info_blurb.current.style.marginTop = "";
            if (div_ref.current.clientHeight > 600) {
                h2_ref.current.style.marginBottom = "-8vh";
            }
            else if (div_ref.current.clientHeight <= 600) {
                h2_ref.current.style.marginBottom = "-5vh";
            }
        } 
        const handleResize = () => {
            if (window.innerWidth < 550) {
                if (mobile_img.current.clientHeight > 300) {
                    info_blurb.current.style.marginTop = "-20vh";
                }
                else {
                    info_blurb.current.style.marginTop = "-10vh";
                }
                if (div_ref.current.clientHeight > 500) {
                    h2_ref.current.style.marginBottom = "-5vh";
                }
                else if (div_ref.current.clientHeight > 350) {
                    h2_ref.current.style.marginBottom = "-3vh";
                }
            }
            else if (window.innerWidth > 550) {
                info_blurb.current.style.marginTop = "";
                if (div_ref.current.clientHeight > 800) {
                    h2_ref.current.style.marginBottom = "-10vh";
                }
                else if (div_ref.current.clientHeight > 350) {
                    h2_ref.current.style.marginBottom = "-5vh";
                }
            } 
        };
        window.addEventListener('resize', handleResize);
    });
    if (props.side === 'right') {
        return (
            <div className='blurb-div-right'>
                <img src={props.img} className='text-img-top' alt='project-img' ref={mobile_img}/>
                <div className='info-blurb' ref={info_blurb}>
                    <h2 style={{ color: props.color }} className='project-title' ref={h2_ref}>{props.name}</h2>
                    <div className='text-img-div-right' ref={div_ref}>
                        <div className='text-img-blurb-right' >
                            <h3 style={{ color: props.color }}>{props.heading}</h3>
                            <h4 style={{ color: props.color }}>{props.subheading}</h4>
                            <ul>
                                {props.text.map((name, index) => {
                                    return <li key={index}>{name}</li>
                                })}
                            </ul>
                            {props.links.map((link, i) => {
                                if (props.links.length === 1) {
                                    return <a href={link}>View code on Github</a>
                                }
                                else {
                                    if (i === 0) {
                                        return <a href={link}
                                        target='_blank'
                                        rel='noreferrer'>View code on Github (Front-End)</a>
                                    }
                                    else if (i === 1) {
                                        return <a href={link}
                                        target='_blank'
                                        rel='noreferrer'>View code on Github (Back-End)</a>
                                    }
                                    else {
                                        return <a href={link}
                                        target='_blank'
                                        rel='noreferrer'>View code on Github (Misc)</a>
                                    }
                                }
                            })}
                        </div>
                        <img src={props.img} className='text-img' alt='project-img' ref={img_ref}/>
                    </div>
                </div>
            </div>
        );
    } else {
        return (
            <div className='blurb-div-left'>
                <img src={props.img} className='text-img-top' alt='project-img' ref={mobile_img}/>
                <div className='info-blurb' ref={info_blurb}>
                    <h2 style={{ color: props.color }} className='project-title' ref={h2_ref}>{props.name}</h2>
                    <div className='text-img-div-left' ref={div_ref}>
                        <div className='text-img-blurb-left'>
                            <h3 style={{ color: props.color }}>{props.heading}</h3>
                            <h4 style={{ color: props.color }}>{props.subheading}</h4>
                            <ul>
                                {props.text.map((name, index) => {
                                    return <li key={index}>{name}</li>
                                })}
                            </ul>
                            {props.links.map((link, i) => {
                                if (props.links.length === 1) {
                                    return <a href={link}>View code on Github</a>
                                }
                                else {
                                    if (i === 0) {
                                        return <a href={link}
                                        target='_blank'
                                        rel='noreferrer'>View code on Github (Front-End)</a>
                                    }
                                    else if (i === 1) {
                                        return <a href={link}
                                        target='_blank'
                                        rel='noreferrer'>View code on Github (Back-End)</a>
                                    }
                                    else {
                                        return <a href={link}
                                        target='_blank'
                                        rel='noreferrer'>View code on Github (Misc)</a>
                                    }
                                }
                            })}
                        </div>
                        <img src={props.img} className='text-img' alt='project-img' ref={img_ref}/>
                    </div>
                </div>
            </div>
        );
    }

}

export default TextBlurbImg;