import React from 'react';
import '../style/Intro.css';
import pic from '../images/me (1).png';

function Intro() {
    return (
        <div id='intro'>
            <div className='intro-text'>
                <h2>Hi, my name is</h2>
                <h1>ERIC DAM</h1>
                <p>I am a software developer who has recently graduated from BCIT, and this is my personal website.</p>
                <a href='#ContactMe'>CONTACT ME</a>
            </div>
            <div className='intro-pic'>
                <img src={pic} alt='ProfilePic' />
            </div>
        </div>
    );
}

export default Intro;