import React, { useEffect, useRef } from 'react';
import '../style/TextBlurb.css';
import '../images/about-text-blurb.svg';
import '../images/mobile-text-blurb.svg';

function TextBlurb(props) {
    const h2_ref = useRef();
    const div_ref = useRef();
    useEffect(() => {
        var detectOverlap = (function () {
            function getPositions(elem) {
                var pos = elem.getBoundingClientRect();
                return [[pos.left, pos.right], [pos.top, pos.bottom]];
            }
        
            function comparePositions(p1, p2) {
                var r1, r2;
                if (p1[0] < p2[0]) {
                  r1 = p1;
                  r2 = p2;
                } else {
                  r1 = p2;
                  r2 = p1;
                }
                return r1[1] > r2[0] || r1[0] === r2[0];
            }
        
            return function (a, b) {
                var pos1 = getPositions(a),
                    pos2 = getPositions(b);
                return comparePositions(pos1[0], pos2[0]) && comparePositions(pos1[1], pos2[1]);
            };
        })();
        var overlapX = (function() {
            function getPositions(elem) {
                var pos = elem.getBoundingClientRect();
                return [pos.left, pos.right];
            }
            function comparePositions(p1, p2) {
                var r1, r2;
                if (p1[1] < p2[1]) {
                    r1 = p1;
                    r2 = p2;
                } else {
                    r1 = p2;
                    r2 = p1;
                }
                if (window.innerWidth >= 800) {
                    return Math.abs((r2[1])/3.5 - r1[1]);
                }
                else if (window.innerWidth < 800) {
                    return 0;
                }
                
            }
            return function (a,b) {
                var pos1 = getPositions(a),
                    pos2 = getPositions(b);
                return comparePositions(pos1, pos2);
            }
        })();

        const handleResize = () => {
            if (detectOverlap(h2_ref.current, div_ref.current)) {
                div_ref.current.style.marginLeft = overlapX(h2_ref.current, div_ref.current) + 'px';
            }
            else if (window.innerWidth < 800) {
                div_ref.current.style.marginLeft = '0';
            }
        }
        if (detectOverlap(h2_ref.current, div_ref.current)) {
            div_ref.current.style.marginLeft = overlapX(h2_ref.current, div_ref.current) + 'px';
        }
        window.addEventListener('resize', handleResize);
    });
    if (props.type === "list") {
        let groupSize = 7;
        let rows = props.list.map((content) => {
            return <li key={content} className="tech-list-item">{content}</li>
        }).reduce((r, element, index) => {
            index % groupSize === 0 && r.push([]);
            r[r.length-1].push(element);
            return r;
        }, []).map((rowContent) => {
            return <ul className="tech-list">{rowContent}</ul>
        });
        return (
            <div className='blurb-div'>
                <h2 style={{color: props.color}} ref={h2_ref}>{props.name}</h2>
                <div className='text-blurb' ref={div_ref}>
                    <h3 style={{color: props.color}}>{props.subtext}</h3>
                    <div id="tech-list">
                        {rows}
                    </div>
                </div>
            </div>
        );
    }
    else {
        return (
            <div className='blurb-div'>
                <h2 style={{color: props.color}} ref={h2_ref}>{props.name}</h2>
                <div className='text-blurb' ref={div_ref}>
                    <h3 style={{color: props.color}}>{props.subtext}</h3>
                    <p>{props.text}</p>
                </div>
            </div>
        );
    }
}

export default TextBlurb;