import React from 'react';
import TextBlurbImg from './TextBlurbImg';
import '../style/Projects.css';
import gloocel from '../images/gloocel.PNG';
import bytesense from '../images/byte_sense.PNG';
import yojana from '../images/yojana.PNG';

let project1_text = ['Created a Flutter application that replaces traditional buzzing and key fob systems for buildings',
        'Received and sent messages from a message broker to perform tasks using a Raspberry Pi',
        'Hosted a database and implemented login and registration features on AWS',
        'Connected the mobile application to a Raspberry Pi prototype with LEDs to simulate a door'];
let project2_text = ['Created a company website for a cybersecurity company',
        'Designed and developed the GUI with the use of React',
        'Implemented login, registration, cart and checkout features']
let project3_text = ['Collaborated with other developers to createa web-based timesheet application',
        'Implemented a login and registration system with tokens in Java',
        'Gathered data from a MySQL database using RESTful APIs',
        'Designed and developed the GUI with the use of React']

let gloocel_links = ['https://github.com/RiceDam/Gloocel_Mobile', 'https://github.com/RiceDam/Gloocel_Django', 'https://github.com/RiceDam/Gloocel_Pi']
let bytesense_links = ['https://github.com/RiceDam/Byte-Sense']
let yojana_links = ['https://github.com/RiceDam/Yojana-Client','https://github.com/RiceDam/Yojana-Backend']

function Projects() {
    return (
        <div id='projects'>
            <fieldset className='project-border'>
                <legend><span>E</span> Projects</legend>
                <TextBlurbImg 
                    name='Project 1' 
                    heading='Gloocel Innovations' 
                    subheading='Technologies used: Flutter, AWS, Django, Python, RabbitMQ, Raspberry Pi, PostreSQL'
                    text={project1_text}
                    color='#78BAF0'
                    img={gloocel}
                    side='right'
                    links={gloocel_links}/>
                <TextBlurbImg 
                    name='Project 2' 
                    heading='ByteSense' 
                    subheading='Technologies used: React, MongoDB, ExpressJS, NodeJS, HTML, CSS'
                    text={project2_text}
                    color='#78BAF0'
                    img={bytesense}
                    side='left'
                    links={bytesense_links}/>
                <TextBlurbImg 
                    name='Project 3' 
                    heading='Yojana' 
                    subheading='Technologies used: Java EE, React'
                    text={project3_text}
                    color='#78BAF0'
                    img={yojana}
                    side='right'
                    links={yojana_links}/>
            </fieldset>
            <p className='project-footer'>Projects</p>
        </div>
            
    );
}

export default Projects;