import React from 'react';
import '../style/AboutMe.css';
import TextBlurb from './TextBlurb';

let about = "I am a software developer who is well versed in Java, C++, C#, C, HTML, CSS and React. My goal is to become a software developer in a company. I live in Vancouver and enjoy problem solving. During my free time, I like to play video games, read manga and drink strawberry milk."
let tech = ["Java", "React", "C#", "C++", "C", "HTML", "CSS", "JavaScript", "Python", "MySQL", "MongoDB", "Google Firebase", "Docker", ".NET", "Django", "NodeJS"]

function AboutMe() {
    return (
        <div id='about-me'>
            <fieldset className='about-border'>
                <legend><span id='e1'>E</span> ABOUT ME <span id='e2'>E</span></legend>
                <TextBlurb 
                    name='WHO I AM' 
                    subtext='I am a graduate from British Columbia Institue of Technology&apos;s Computer Systems Technology program.' 
                    text={about}
                    color='#78BAF0'
                    type="text"/>
                <TextBlurb
                    name='TECHNOLOGIES'
                    subtext='I immersed myself in a variety of technologies, frameworks, and programming languages as a BCIT grad. Here&apos;s a list of them.' 
                    text='testing'
                    color='#4FBABD'
                    list={tech}
                    type="list"/>
            </fieldset>
            <p className='about-footer'>About Me</p>
        </div>
            
    );
}

export default AboutMe;