import React, { useRef } from 'react';
import '../style/Navbar.css';

function Navbar() {
    const menu_ref = useRef();

    var openMenu = () => {
        menu_ref.current.style.height = "100%";
    }

    var closeMenu = () => {
        menu_ref.current.style.height = "0";
    }
    return (
        <div className='Navbar'>
            <div className='links'>
                <div className='link' id='left'>
                    <a href='#about-me'>ABOUT</a>
                    <a href='#projects'>PROJECTS</a>
                </div>
                <div className='link' id='trap'>
                    <a href='#ContactMe'>CONTACT</a>
                </div>
                <div className='link' id='right'>
                    <a href='https://drive.google.com/drive/folders/17cdw8GQJ90FAYoKtLCaaHJRPmcEfDhuI?usp=sharing'
                        target='_blank'
                        rel='noreferrer'>
                        RESUME
                    </a>
                    <a href='https://drive.google.com/drive/folders/17cdw8GQJ90FAYoKtLCaaHJRPmcEfDhuI?usp=sharing'
                        target='_blank'
                        rel='noreferrer'>
                        COVER LETTER
                    </a>
                </div>
            </div>
            <button id="menuButton" onClick={openMenu}>Menu</button>
            <div className='mobile-menu' ref={menu_ref}>
                <button id="closeMenuButton" onClick={closeMenu}>x</button>
                <a href='#about-me' onClick={closeMenu}>ABOUT</a>
                <a href='#projects' onClick={closeMenu}>PROJECTS</a>
                <a href='#ContactMe' onClick={closeMenu}>CONTACT</a>
                <a href='https://drive.google.com/drive/folders/17cdw8GQJ90FAYoKtLCaaHJRPmcEfDhuI?usp=sharing'
                    target='_blank'
                    rel='noreferrer'
                    onClick={closeMenu}>
                    RESUME
                </a>
                <a href='https://drive.google.com/drive/folders/17cdw8GQJ90FAYoKtLCaaHJRPmcEfDhuI?usp=sharing'
                    target='_blank'
                    rel='noreferrer'
                    onClick={closeMenu}>
                    COVER LETTER
                </a>
            </div>
        </div>
    );
}

export default Navbar;